{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラの正式キックオフおよび発足を承認し、プロジェクトが正式启动したことを確認する",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例会議を毎週水曜日10時から1時間枠で開催することとし、各部署より代表者1名の参加およびリモート参加可とする",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "移行方式として、拠点をグループに分けて段階的に切り替える「段階移行（B案）」を採用することを決定する",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "本番リリースの目標日程を当初の9月末から10月15日に変更し、確定させる",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "システム切替作業は土曜日の深夜帯〜日曜日に行うことを原則とすることを決定する",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "認証およびマスタ配信基盤について、サクラ商事との共同利用（第3案）を進める方針を確定させる",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "ユーザー権限のロール定義については、新システムでは既存定義を流用し、作り直しは移行後の運用改善案件として別途立てることを決定する",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "開発ベンダーはコマツバ・ソリューションズ社を選定することとし、社内稟議を進めることを決定する",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D9",
      "content": "障害対応の一次受け窓口を情報システム部から品質保証部（QA）に変更することを決定する",
      "decided_by": "桐生 遥"
    }
  ],
